14→public class FunctionReturnTypeSpacingRule :
15→    StandardRule("function-return-type-spacing"),
16→    Rule.Experimental {
17→    override fun beforeVisitChildNodes(
18→        node: ASTNode,
19→        autoCorrect: Boolean,
20→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
21→    ) {
22→        node.firstChildNode
23→        node
24→            .takeIf { node.elementType == FUN }
25→            ?.let { node.findChildByType(COLON) }
26→            ?.let { colonNode ->
27→                removeWhiteSpaceBetweenClosingParenthesisAndColon(colonNode, emit, autoCorrect)
28→                fixWhiteSpaceBetweenColonAndReturnType(colonNode, emit, autoCorrect)
29→            }
30→    }
31→
32→    private fun removeWhiteSpaceBetweenClosingParenthesisAndColon(
33→        node: ASTNode,
34→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
35→        autoCorrect: Boolean,
36→    ) {
37→        require(node.elementType == COLON)
38→        node
39→            .prevLeaf()
40→            ?.takeIf { it.elementType == WHITE_SPACE }
41→            ?.let { whitespaceBeforeColonNode ->
42→                emit(whitespaceBeforeColonNode.startOffset, "Unexpected whitespace", true)
43→                if (autoCorrect) {
44→                    whitespaceBeforeColonNode.treeParent?.removeChild(whitespaceBeforeColonNode)
45→                }
46→            }
47→    }
