        node: ASTNode,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        autoCorrect: Boolean,
    ) {
        require(node.elementType == COLON)
        node
            .nextLeaf()
            ?.takeIf { it.elementType == WHITE_SPACE }
            .let { whiteSpaceAfterColon ->
                val expectedWhitespace = determineExpectedWhitespace(node)
                if (whiteSpaceAfterColon?.text != expectedWhitespace) {
                    emit(node.startOffset, "Single space expected between colon and return type", true)
                    if (autoCorrect) {
                        node.upsertWhitespaceAfterMe(expectedWhitespace)
                    }
                }
            }
    }

    private fun determineExpectedWhitespace(colonNode: ASTNode): String {
        // Check if putting return type on same line would exceed max line length
        if (wouldExceedMaxLineLength(colonNode)) {
            // Keep the newline with proper indentation
            val functionNode = colonNode.treeParent
            val indent = functionNode.lineIndent()
            return "\n" + indent + editorConfigIndent.indent
        }
        return " "
    }

    private fun wouldExceedMaxLineLength(colonNode: ASTNode): Boolean {
        // Find the return type text
        var returnTypeNode = colonNode.nextLeaf()
        while (returnTypeNode != null && returnTypeNode.elementType == WHITE_SPACE) {
            returnTypeNode = returnTypeNode.nextLeaf()
        }

        if (returnTypeNode == null) {
            return false
        }

        // Calculate what the line would be if we put return type on same line
        // Find the start of the current line
        var lineStart = colonNode
        var prevNode = lineStart.prevLeaf()
        while (prevNode != null && !prevNode.text.contains('\n')) {
            lineStart = prevNode
            prevNode = lineStart.prevLeaf()
        }

        // Calculate line length: from line start to colon + ": " + return type
        var lengthBeforeColon = 0
        var currentNode = lineStart
        while (currentNode != colonNode) {
            lengthBeforeColon += currentNode.textLength
            currentNode = currentNode.nextLeaf() ?: break
        }
        lengthBeforeColon += colonNode.textLength // Add the colon itself

        // Get the return type text (including generic parameters if any)
        val returnTypeText = getReturnTypeText(returnTypeNode)

        val projectedLength = lengthBeforeColon + 1 + returnTypeText.length // +1 for the space

        return projectedLength > maxLineLength
    }

    private fun getReturnTypeText(startNode: ASTNode): String {
        val sb = StringBuilder()
        var currentNode: ASTNode? = startNode

        // Collect return type text until we hit whitespace with newline, opening brace, or EQ
        while (currentNode != null) {
            when {
                currentNode.elementType == WHITE_SPACE && currentNode.text.contains('\n') -> break
                currentNode.elementType.toString() == "LBRACE" -> break
                currentNode.elementType.toString() == "EQ" -> break
                currentNode.elementType == WHITE_SPACE -> {
                    // For whitespace without newline, just add a space
                    if (sb.isNotEmpty()) {
                        sb.append(" ")
                    }
                }
                else -> sb.append(currentNode.text)
            }
            currentNode = currentNode.nextLeaf()
        }

        return sb.toString().trim()
    }"}

{"file_path": "/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/FunctionReturnTypeSpacingRuleMaxLineLengthTest.kt", "content": "package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class FunctionReturnTypeSpacingRuleMaxLineLengthTest {
    private val functionReturnTypeSpacingRuleAssertThat = assertThatRule { FunctionReturnTypeSpacingRule() }

    @Test
    fun `Given a function with return type that would exceed max line length when placed on same line, keep the newline`() {
        val code =
            """
            fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction():
                AndAlsoALongReturnType {
            }
            """.trimIndent()
        functionReturnTypeSpacingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 120)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a function with return type that would NOT exceed max line length, put return type on same line`() {
        val code =
            """
            fun shortFunctionName():
                String {
            }
            """.trimIndent()
        val formattedCode =
            """
            fun shortFunctionName(): String {
            }
            """.trimIndent()
        functionReturnTypeSpacingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 120)
            .hasLintViolation(1, 24, "Single space expected between colon and return type")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a function with return type on same line that exceeds max line length, wrap to newline`() {
        val code =
            """
            fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction(): AndAlsoALongReturnType {
            }
            """.trimIndent()
        val formattedCode =
            """
            fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction():
                AndAlsoALongReturnType {
            }
            """.trimIndent()
        functionReturnTypeSpacingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 120)
            .hasLintViolation(1, 107, "Single space expected between colon and return type")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given an indented function with return type that would exceed max line length, keep the newline with proper indent`() {
        val code =
            """
            class Foo {
                fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction():
                    AndAlsoALongReturnType {
                }
            }
            """.trimIndent()
        functionReturnTypeSpacingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 120)
            .hasNoLintViolations()
    }

    @Test
    fun `Given an indented function with return type on same line that exceeds max line length, wrap with proper indent`() {
        val code =
            """
            class Foo {
                fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction(): AndAlsoALongReturnType {
                }
            }
            """.trimIndent()
        val formattedCode =
            """
            class Foo {
                fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction():
                    AndAlsoALongReturnType {
                }
            }
            """.trimIndent()
        functionReturnTypeSpacingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 120)
            .hasLintViolation(2, 111, "Single space expected between colon and return type")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a function with return type that fits within max line length, put on same line`() {
        val code =
            """
            fun foo(): String = "some-result"
            """.trimIndent()
        functionReturnTypeSpacingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 120)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a function with generic return type that would exceed max line length, keep newline`() {
        val code =
            """
            fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction():
                List<String> {
            }
            """.trimIndent()
        functionReturnTypeSpacingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 120)
            .hasNoLintViolations()
    }
}
"}

