import com.pinterest.ktlint.rule.engine.core.api.editorconfig.MAX_LINE_LENGTH_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Test for GitHub issue: experimental:function-return-type-spacing can violate max-line rule
 * 
 * The issue describes that the function-return-type-spacing rule would reformat code
 * from a newline after the colon to putting the return type on the same line, even when
 * this would violate the max-line-length rule.
 */
class FunctionReturnTypeSpacingRuleIssueTest {
    private val functionReturnTypeSpacingRuleAssertThat = assertThatRule { FunctionReturnTypeSpacingRule() }

    @Test
    fun `Issue - function with long name and return type should keep newline when line would exceed max length`() {
        // This is the exact code from the GitHub issue
        val code =
            """
            fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction():
                AndAlsoALongReturnType {

            }
            """.trimIndent()

        // With max_line_length = 120, the code should NOT be reformatted
        // because putting the return type on the same line would create a line of 127 characters
        functionReturnTypeSpacingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 120)
            .hasNoLintViolations()
    }

    @Test
    fun `Issue - function with long name on same line should wrap when exceeding max length`() {
        // This is what the issue complained about - the rule would create this
        val code =
            """
            fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction(): AndAlsoALongReturnType {

            }
            """.trimIndent()

        val formattedCode =
            """
            fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction():
                AndAlsoALongReturnType {

            }
            """.trimIndent()

        // Now with the fix, the rule should detect that the line is too long and wrap it
        functionReturnTypeSpacingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 120)
            .hasLintViolation(1, 102, "Single space expected between colon and return type")
            .isFormattedAs(formattedCode)
    }
}
"}

